102	inline auto spawn_qemu(const std::string& binary,
103	                       const std::string& elf,
104	                       uint16_t gdb_port,
105	                       const std::string& shared_mem_path = {},
106	                       uint64_t shared_mem_size = 0) -> pid_t
107	{
108	  const pid_t pid = ::fork();
109	  if (pid < 0)
110	    throw std::runtime_error(std::string{"spawn_qemu: fork: "}
111	                             + std::strerror(errno));
112	  if (pid == 0) {
113	    const std::string gdb_arg = "tcp::" + std::to_string(gdb_port);
114	    const std::string mem_obj = "memory-backend-file,id=mem,share=on,mem-path="
115	                              + shared_mem_path
116	                              + ",size=" + std::to_string(shared_mem_size);
117	    std::vector<const char*> argv;
118	    argv.push_back(binary.c_str());
119	    if (!shared_mem_path.empty()) {
120	      argv.push_back("-object");
121	      argv.push_back(mem_obj.c_str());
122	      argv.push_back("-machine");
123	      argv.push_back("virt,memory-backend=mem");
124	    } else {
125	      argv.push_back("-M");
126	      argv.push_back("virt");
127	    }
128	    argv.push_back("-bios");
129	    argv.push_back("none");
130	    argv.push_back("-nographic");
131	    argv.push_back("-semihosting-config");
132	    argv.push_back("enable=on,target=native");
133	    argv.push_back("-kernel");
134	    argv.push_back(elf.c_str());
135	    argv.push_back("-gdb");
136	    argv.push_back(gdb_arg.c_str());
137	    argv.push_back("-S");
138	    argv.push_back(nullptr);
139	
140	    ::execv(binary.c_str(), const_cast<char* const*>(argv.data()));
141	    std::fprintf(stderr, "exec %s: %s\n", binary.c_str(),
142	                 std::strerror(errno));
143	    ::_exit(127);
144	  }
145	  return pid;
146	}
