195	// Sends one P packet whose body is built by the supplied encoder. A
196	// missing register name is silently skipped: not every QEMU build
197	// advertises every PMP slot or extension CSR, so absence isn't fatal.
198	template<class Encoder>
199	inline void try_write_named(gdbstub::Session& sess,
200	                            const gdbstub::RegMap& map,
201	                            const std::string& name,
202	                            Encoder&& encoder)
203	{
204	  const auto reg_num = map.find(name);
205	  if (!reg_num) return;
206	  auto reply = sess.send_command(encoder(*reg_num));
207	  if (reply != "OK")
208	    throw std::runtime_error("gdbstub: P packet for " + name + " replied "
209	                             + reply);
210	}
211	
212	inline void try_write_named_u64(gdbstub::Session& sess,
213	                                const gdbstub::RegMap& map,
214	                                const std::string& name,
215	                                uint64_t value)
216	{
217	  try_write_named(sess, map, name, [&](unsigned r) {
218	    return gdbstub::encode_p_body(r, value);
219	  });
220	}
221	
222	inline void try_write_named_bytes(gdbstub::Session& sess,
223	                                  const gdbstub::RegMap& map,
224	                                  const std::string& name,
225	                                  const uint8_t* bytes,
226	                                  std::size_t n)
227	{
228	  try_write_named(sess, map, name, [&](unsigned r) {
229	    return gdbstub::encode_p_body_bytes(r, bytes, n);
230	  });
231	}
