256	// Restores x1..x31, PC, FPR (if HYBRID_FLAG_FP), M-mode CSRs, PMP, and
257	// vector data regs (if HYBRID_FLAG_V) into the QEMU vCPU via the gdbstub
258	// at `port`, then continues. Caller is responsible for waitpid().
259	inline void restore_state_via_gdbstub(uint16_t port,
260	                                      const hybrid_state_v1& state,
261	                                      pid_t child_pid = -1)
262	{
263	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
264	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5),
265	                                          child_pid);
266	  spdlog::info("hybrid handback: connected, discovering register map");
267	  gdbstub::Session sess{fd};
268	
269	  const auto reg_map = detail::discover_reg_map(sess);
270	  spdlog::info("hybrid handback: {} registers advertised, restoring state",
271	               reg_map.size());
272	
273	  // RV64 core: x0..x31 = 0..31, pc = 32. Hard-coded because the core
274	  // feature is always first.
275	  for (unsigned i = 1; i < 32; ++i) {
276	    auto reply = sess.send_command(gdbstub::encode_p_body(i, state.gpr[i]));
277	    if (reply != "OK")
278	      throw std::runtime_error(
279	        "gdbstub: P packet for x" + std::to_string(i) + " replied " + reply);
280	  }
281	  auto reply = sess.send_command(gdbstub::encode_p_body(32, state.pc));
282	  if (reply != "OK")
283	    throw std::runtime_error("gdbstub: P32 (pc) replied " + reply);
284	
285	  if ((state.flags & HYBRID_FLAG_FP) != 0u)
286	    for (std::size_t i = 0; i < 32; ++i)
287	      detail::try_write_named_u64(sess, reg_map, hybrid_fpr_names[i],
288	                                  state.fpr[i]);
289	
290	  for (const auto& slot : detail::kCsrByName)
291	    detail::try_write_named_u64(sess, reg_map, slot.first,
292	                                state.*(slot.second));
293	
294	  for (uint16_t i = 0; i < HYBRID_PMP_CFG_NUM; ++i)
295	    detail::try_write_named_u64(sess, reg_map, "pmpcfg" + std::to_string(i),
296	                                state.pmpcfg[i]);
297	  for (uint16_t i = 0; i < HYBRID_PMP_ADDR_NUM; ++i)
298	    detail::try_write_named_u64(sess, reg_map, "pmpaddr" + std::to_string(i),
299	                                state.pmpaddr[i]);
300	
301	  if ((state.flags & HYBRID_FLAG_V) != 0u && state.vlenb > 0u
302	      && state.vlenb <= HYBRID_VLEN_BYTES_MAX) {
303	    detail::try_write_named_u64(sess, reg_map, "vstart", state.vstart);
304	    const std::size_t vbytes = static_cast<std::size_t>(state.vlenb);
305	    for (uint16_t i = 0; i < 32; ++i) {
306	      const std::string name = "v" + std::to_string(i);
307	      detail::try_write_named_bytes(
308	        sess, reg_map, name,
309	        &state.vreg[static_cast<std::size_t>(i) * HYBRID_VLEN_BYTES_MAX],
310	        vbytes);
311	    }
312	  }
313	
314	  spdlog::info("hybrid handback: continuing target");
315	  sess.cont();
316	}
