318	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
319	// status (or 128 + signal for abnormal termination).
320	inline auto run_qemu_handback(const std::string& qemu_binary,
321	                              const std::string& elf_path,
322	                              const hybrid_state_v1& state,
323	                              const std::string& shared_mem_path = {},
324	                              uint64_t shared_mem_size = 0) -> int
325	{
326	  const auto port = detail::pick_free_port();
327	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
328	               qemu_binary, port);
329	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port,
330	                                       shared_mem_path, shared_mem_size);
331	
332	  try {
333	    restore_state_via_gdbstub(port, state, pid);
334	  } catch (const detail::ChildExitedDuringConnect& d) {
335	    return d.status;
336	  } catch (...) {
337	    ::kill(pid, SIGKILL);
338	    int wstat = 0;
339	    ::waitpid(pid, &wstat, 0);
340	    throw;
341	  }
342	
343	  int wstat = 0;
344	  if (::waitpid(pid, &wstat, 0) < 0)
345	    throw std::runtime_error(std::string{"waitpid: "}
346	                             + std::strerror(errno));
347	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
348	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
349	  return -1;
350	}
