1	// TCP-backed GDB Remote Serial Protocol session. Wraps an already-connected
2	// socket fd; the higher-level qemu_handback orchestration spawns QEMU and
3	// passes the fd in.
4	
5	#pragma once
6	
7	#include "hybrid/gdbstub_client.hpp"
8	
9	#include <spdlog/spdlog.h>
10	
11	#include <sys/socket.h>
12	#include <sys/time.h>
13	#include <unistd.h>
14	
15	#include <cerrno>
16	#include <cstdint>
17	#include <cstring>
18	#include <stdexcept>
19	#include <string>
20	#include <string_view>
21	
22	namespace hybrid::gdbstub
23	{
24	
25	class Session
26	{
27	public:
28	  // 5 s recv timeout: a peer that opens the gdbstub port but never replies
29	  // (e.g. a misbehaving QEMU build) must not hang vsim indefinitely.
30	  static constexpr long kRecvTimeoutSeconds = 5;
31	
32	  explicit Session(int fd)
33	      : fd_{fd}
34	  {
35	    timeval tv{kRecvTimeoutSeconds, 0};
36	    ::setsockopt(fd_, SOL_SOCKET, SO_RCVTIMEO, &tv, sizeof(tv));
37	  }
38	
39	  Session(const Session&)            = delete;
40	  Session& operator=(const Session&) = delete;
41	
42	  Session(Session&& o) noexcept
43	      : fd_{o.fd_}
44	  {
45	    o.fd_ = -1;
46	  }
47	
48	  ~Session()
49	  {
50	    if (fd_ >= 0) ::close(fd_);
51	  }
52	
53	  // Sends $body#cs, waits for `+` ack, reads and acks one response packet,
54	  // returns the response body. Throws on socket errors or protocol violations.
55	  auto send_command(std::string_view body) -> std::string
56	  {
57	    const auto pkt = encode_packet(body);
58	    spdlog::debug("gdbstub send: {}", pkt);
59	    send_raw(pkt);
60	    expect_ack();
61	    auto resp = recv_packet();
62	    spdlog::debug("gdbstub recv: {}", resp);
63	    send_raw("+");
64	    return resp;
65	  }
66	
67	  // Sends $c#cs and waits only for the ack. The target runs until it exits
68	  // on its own (e.g., semihosting) -- caller waitpid()s the QEMU process.
69	  void cont()
70	  {
71	    send_raw(encode_continue());
72	    expect_ack();
73	  }
74	
75	private:
76	  void send_raw(std::string_view data)
77	  {
78	    std::size_t off = 0;
79	    while (off < data.size()) {
80	      const ssize_t n =
81	        ::send(fd_, data.data() + off, data.size() - off, 0);
82	      if (n < 0) {
83	        if (errno == EINTR) continue;
84	        throw std::runtime_error(std::string{"gdbstub::Session::send: "}
85	                                 + std::strerror(errno));
86	      }
87	      off += static_cast<std::size_t>(n);
88	    }
89	  }
90	
91	  auto recv_byte() -> char
92	  {
93	    char c;
94	    while (true) {
95	      const ssize_t n = ::recv(fd_, &c, 1, 0);
96	      if (n == 1) return c;
97	      if (n == 0)
98	        throw std::runtime_error("gdbstub::Session: peer closed");
99	      if (errno == EINTR) continue;
100	      if (errno == EAGAIN || errno == EWOULDBLOCK)
101	        throw std::runtime_error("gdbstub::Session: recv timeout");
102	      throw std::runtime_error(std::string{"gdbstub::Session::recv: "}
103	                               + std::strerror(errno));
104	    }
105	  }
106	
107	  void expect_ack()
108	  {
109	    const auto c = recv_byte();
110	    if (c == '+') return;
111	    if (c == '-')
112	      throw std::runtime_error("gdbstub::Session: peer requested resend");
113	    throw std::runtime_error(
114	      std::string{"gdbstub::Session: expected ack, got "} + c);
115	  }
116	
117	  // Reads `$body#cs`, validates checksum, returns body. Discards any leading
118	  // out-of-frame bytes (some stubs emit unsolicited stop notifications).
119	  auto recv_packet() -> std::string
120	  {
121	    while (recv_byte() != '$') {}
122	    std::string body;
123	    while (true) {
124	      const auto c = recv_byte();
125	      if (c == '#') break;
126	      body.push_back(c);
127	    }
128	    const auto cs_hi = recv_byte();
129	    const auto cs_lo = recv_byte();
130	    const std::string framed = "$" + body + "#" + cs_hi + cs_lo;
131	    auto parsed = parse_packet(framed);
132	    if (!parsed)
133	      throw std::runtime_error("gdbstub::Session: bad checksum");
134	    return *parsed;
135	  }
136	
137	  int fd_;
138	};
139	
140	}  // namespace hybrid::gdbstub
