315	    ? MemoryRegion{args.shared_mem_base,
316	                   args.shared_mem_base + args.shared_mem_size - 1}
317	    : MemoryRegion{RAM_BASE, RAM_END};
318	  const MemoryRegion ram_alias_region = shared_ram
319	    ? MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
320	                   SimpleMemory<32>::INVALID_ADDRESS}
321	    : MemoryRegion{RAM_ALIAS_BASE, RAM_ALIAS_END};
