372	    }
373	
374	    if (!args.kanata_file.empty())
375	      sim.enable_kanata(args.kanata_file, args.objdump_file, loop_gate);
376	
377	    if (!args.clarity_file.empty())
378	      sim.enable_clarity(args.clarity_file, args.objdump_file, loop_gate);
379	
380	    if (!args.elf_file.empty() && !args.continue_ctx)
381	      sim.load_elf(args.elf_file);
382	
383	    // Apply per-hart reset vector overrides (after load_elf sets defaults)
384	    for (const auto& s: args.reset_vectors) {
385	      auto [hart, addr] = parse_reset_vector(s);
386	      if (hart) {
387	        sim.set_reset_vector(*hart, addr);
388	      } else {
389	        for (size_t i = 0; i < sim.platform.reset_vector.size(); ++i)
390	          sim.set_reset_vector(i, addr);
391	      }
392	    }
393	
394	    if (args.continue_ctx)
395	      spdlog::info("You're resuming program from the given context");
396	
397	    if (args.jtag_port)
398	      sim.init_debug_port(args.jtag_port.value());
399	
400	    if (!args.jtag_port && args.elf_file.empty() && !args.continue_ctx
401	        && args.resume_from_qemu.empty())
402	      throw std::runtime_error(
403	        "Required arg : program, --jtag-port, or --resume-from-qemu");
404	
405	    if (args.continue_ctx || args.save_ctx) {
406	      std::string_view s = args.context_dir;
407	      if (std::filesystem::exists(s) && !std::filesystem::is_directory(s))
408	        throw std::runtime_error("Error: Path " + std::string{s}
409	                                 + " exists but is not a directory.");
410	      if (!std::filesystem::exists(s)) {
411	        try {
412	          std::filesystem::create_directories(s);
413	        } catch (const std::filesystem::filesystem_error& e) {
414	          throw std::runtime_error(std::string{"Failed to create directory: "}
415	                                   + e.what());
416	        }
417	      }
418	      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
419	    }
420	
421	    sim.reset();
422	
423	    if (!args.resume_from_qemu.empty())
424	      sim.apply_resume_from_qemu(args.resume_from_qemu);
425	
426	    if (!args.handoff_out.empty())
427	      sim.enable_hybrid_handoff(args.elf_file, args.handoff_out);
428	
429	    const int exit_code = sim.run();
430	
431	    sim.cpu.final();
432	
433	    if (exit_code == hybrid::kExitHandoffToQemu && !args.qemu_binary.empty()) {
434	      hybrid_state_v1 state{};
435	      std::ifstream sf(args.handoff_out, std::ios::binary);
436	      if (!sf)
437	        throw std::runtime_error("handoff: cannot read drained state file: "
438	                                 + args.handoff_out);
439	      sf.read(reinterpret_cast<char*>(&state), sizeof(state));
440	      if (!sf)
441	        throw std::runtime_error("handoff: short read of drained state file");
442	      return hybrid::run_qemu_handback(args.qemu_binary, args.elf_file, state,
443	                                       args.shared_mem_path,
444	                                       args.shared_mem_size);
445	    }
446	
447	    const auto t1 = std::chrono::steady_clock::now();
448	    const auto cycles = sim.get_cycles();
449	    spdlog::info("{} cycles simulated", cycles);
450	    if (cycles > 0) {
451	      const auto ms =
452	        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
453	      spdlog::info("{}.{:03}s elapsed, {:.3f}Hz", ms.count() / 1000,
454	                   ms.count() % 1000,
455	                   double(cycles) / double(ms.count()) * 1000.0);
456	    }
457	    return exit_code;
458	  };
459	
460	  return do_sim.operator()<VSIM_CPU_INTERFACE_CLASS>();
461	
462	} catch (const std::exception& e) {
463	  spdlog::critical("fatal exception: {}\n", e.what());
464	  std::exit(EXIT_FAILURE);
465	} catch (...) {
466	  std::terminate();
467	}
