1	// StateDrain halts the hart via the Debug Module and populates a
2	// hybrid_state_v1 with the architectural register file. Reuses
3	// ResumeDriver's DM register constants and DmiBus interface.
4	
5	#pragma once
6	
7	#include "hybrid/abstract_command.hpp"
8	#include "hybrid/dmi_poll.hpp"
9	#include "hybrid/resume_driver.hpp"
10	#include "hybrid/state_abi.h"
11	
12	#include <algorithm>
13	#include <cstdint>
14	
15	namespace hybrid
16	{
17	
18	class StateDrain
19	{
20	public:
21	  using RD = ResumeDriver;
22	
23	  explicit StateDrain(DmiBus& bus)
24	      : bus_{bus}
25	  {}
26	
27	  // Drain x1..x31 + PC. FP/CSR/V slots remain zero; merge them in via
28	  // drain_with_passthrough when the QEMU 1 snapshot is available.
29	  auto drain() -> hybrid_state_v1
30	  {
31	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive);
32	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive | RD::kDmcontrolHaltreq);
33	    poll_until_set(bus_, RD::kDmstatus, RD::kDmstatusAllhalted,
34	                   "StateDrain halt");
35	
36	    hybrid_state_v1 state{};
37	    state.magic   = HYBRID_STATE_MAGIC;
38	    state.version = HYBRID_STATE_VERSION;
39	    state.flags   = HYBRID_FLAG_RV64;
40	    state.priv    = 3;
41	
42	    for (uint16_t i = 1; i < 32; ++i)
43	      state.gpr[i] = read_64bit_register(regno_gpr(i));
44	
45	    state.pc = read_64bit_register(regno_csr(RD::kCsrDpc));
46	    return state;
47	  }
48	
49	  // Returns the input snapshot with x1..x31 and PC overwritten by a fresh
50	  // DM read. Lets the round-trip preserve FP/CSR/V state without paying
51	  // the ~100x DM Abstract Command overhead for fields the ROI didn't
52	  // modify, and stays correct when new fields are added to the wire.
53	  auto drain_with_passthrough(const hybrid_state_v1& input) -> hybrid_state_v1
54	  {
55	    auto state       = input;
56	    const auto fresh = drain();
57	    std::copy(std::begin(fresh.gpr) + 1, std::end(fresh.gpr),
58	              std::begin(state.gpr) + 1);
59	    state.pc = fresh.pc;
60	    return state;
61	  }
62	
63	private:
64	  auto read_64bit_register(uint16_t regno) -> uint64_t
65	  {
66	    bus_.write(RD::kCommand, access_register_command(regno, AarSize::Bits64,
67	                                                     /*write=*/false));
68	    poll_until_clear(bus_, RD::kAbstractcs, RD::kAbstractcsBusy,
69	                     "StateDrain read_register");
70	    // If the hardware DM does not implement Abstract access for this
71	    // register, cmderr is set sticky and DATA0/DATA1 hold stale bytes.
72	    // Clear the error and report 0 for that field so the next read can
73	    // proceed - a missing CSR mirrors as zero rather than corrupting the
74	    // adjacent slot.
75	    const auto status = bus_.read(RD::kAbstractcs);
76	    if ((status & RD::kAbstractcsCmderrMask) != 0u) {
77	      bus_.write(RD::kAbstractcs, RD::kAbstractcsCmderrMask);
78	      return 0u;
79	    }
80	    const uint64_t lo = bus_.read(RD::kData0);
81	    const uint64_t hi = bus_.read(RD::kData1);
82	    return lo | (hi << 32);
83	  }
84	
85	  DmiBus& bus_;
86	};
87	
88	}  // namespace hybrid
