1	// MmapBacking + SimpleMemory glued together: writes via TLM land on disk,
2	// bytes pre-placed by an external owner are visible via TLM reads.
3	
4	#include "platform/mmap_backing.hpp"
5	#include "platform/simple_memory.hpp"
